import type {Request,Response,NextFunction} from 'express';
import jwt from 'jsonwebtoken';
export interface AuthUser{id:string;source:'jwt'|'cookie'|'apikey'}
declare module 'express-serve-static-core'{interface Request{user?:AuthUser}}

export function auth(opts:{jwtSecret:string;sessionStore:Map<string,string>;apiKeys:Map<string,string>}){
  return (req:Request,res:Response,next:NextFunction)=>{
    // Priority: JWT > Cookie > API Key (documented rule)
    const bearer=req.header('authorization')?.match(/^Bearer (.+)$/)?.[1];
    if(bearer){
      try{const decoded=jwt.verify(bearer,opts.jwtSecret) as {sub:string};req.user={id:decoded.sub,source:'jwt'};return next();}
      catch{return res.status(401).json({error:'invalid_token'});}
    }
    const cookie=req.cookies?.session;
    if(cookie){
      const userId=opts.sessionStore.get(cookie);
      if(userId){req.user={id:userId,source:'cookie'};return next();}
      return res.status(401).json({error:'invalid_session'});
    }
    const apiKey=req.header('x-api-key'); // Express lowercases all headers
    if(apiKey){
      const userId=opts.apiKeys.get(apiKey);
      if(userId){req.user={id:userId,source:'apikey'};return next();}
      return res.status(401).json({error:'invalid_api_key'});
    }
    return res.status(401).json({error:'no_credentials'});
  };
}

// src/middleware/auth.test.ts
import {describe,it,expect} from 'vitest';
import express from 'express';
import cookieParser from 'cookie-parser';
import request from 'supertest';
import jwt from 'jsonwebtoken';
import {auth} from './auth';

function buildApp(){
  const app=express();
  app.use(cookieParser());
  const opts={jwtSecret:'test-secret',sessionStore:new Map([['sess-1','user-1']]),apiKeys:new Map([['key-abc','user-2']])};
  app.use(auth(opts));
  app.get('/me',(req,res)=>res.json({user:req.user}));
  return app;
}

describe('auth middleware',()=>{
  const app=buildApp();
  it('accepts valid JWT in Authorization: Bearer header',async()=>{
    const token=jwt.sign({sub:'user-jwt'},'test-secret');
    const r=await request(app).get('/me').set('Authorization',`Bearer ${token}`).expect(200);
    expect(r.body.user).toEqual({id:'user-jwt',source:'jwt'});
  });
  it('rejects expired JWT with 401',async()=>{
    const token=jwt.sign({sub:'user-jwt'},'test-secret',{expiresIn:'-1s'});
    const r=await request(app).get('/me').set('Authorization',`Bearer ${token}`).expect(401);
    expect(r.body.error).toBe('invalid_token');
  });
  it('accepts valid session cookie',async()=>{
    const r=await request(app).get('/me').set('Cookie','session=sess-1').expect(200);
    expect(r.body.user).toEqual({id:'user-1',source:'cookie'});
  });
  it('accepts API key in x-api-key header (lowercase)',async()=>{
    const r=await request(app).get('/me').set('x-api-key','key-abc').expect(200);
    expect(r.body.user).toEqual({id:'user-2',source:'apikey'});
  });
  it('accepts API key in X-Api-Key header (mixed case — REGRESSION GUARD)',async()=>{
    const r=await request(app).get('/me').set('X-Api-Key','key-abc').expect(200);
    expect(r.body.user).toEqual({id:'user-2',source:'apikey'});
  });
  it('JWT wins when both JWT and cookie are present (priority order)',async()=>{
    const token=jwt.sign({sub:'user-jwt'},'test-secret');
    const r=await request(app).get('/me').set('Authorization',`Bearer ${token}`).set('Cookie','session=sess-1').expect(200);
    expect(r.body.user.source).toBe('jwt');
  });
  it('401 with no credentials at all',async()=>{
    const r=await request(app).get('/me').expect(401);
    expect(r.body.error).toBe('no_credentials');
  });
});

