export interface Item{id:string;createdAt:number}
export interface Page<T>{items:T[];page:number;total:number;perPage:number}
export function paginate<T extends Item>(items:T[],page:number,perPage:number):Page<T>{
  if(page<1||perPage<1)throw new Error('page and perPage must be >= 1');
  // Sort by createdAt desc, then by id asc (tie-breaker) — STABLE order
  const sorted=[...items].sort((a,b)=>b.createdAt-a.createdAt||a.id.localeCompare(b.id));
  const start=(page-1)*perPage;
  return {items:sorted.slice(start,start+perPage),page,total:items.length,perPage};
}

// src/pagination/paginate.property.test.ts
import {describe,it,expect} from 'vitest';
import fc from 'fast-check';
import {paginate,type Item} from './paginate';

const itemArb=fc.record<Item>({id:fc.uuid(),createdAt:fc.integer({min:0,max:5})}); // small range → forces ties
const inputArb=fc.array(itemArb,{minLength:0,maxLength:50}).map(items=>{
  // Ensure unique IDs (the property only holds with unique IDs)
  const seen=new Set<string>();
  return items.filter(i=>{if(seen.has(i.id))return false;seen.add(i.id);return true;});
});

describe('paginate properties',()=>{
  it('union of all pages equals input set',()=>{
    fc.assert(fc.property(inputArb,fc.integer({min:1,max:10}),(items,perPage)=>{
      const totalPages=Math.max(1,Math.ceil(items.length/perPage));
      const allIds=new Set<string>();
      for(let p=1;p<=totalPages;p++){
        for(const it of paginate(items,p,perPage).items)allIds.add(it.id);
      }
      return allIds.size===items.length&&items.every(i=>allIds.has(i.id));
    }),{numRuns:500});
  });
  it('any two pages are disjoint (no item appears twice)',()=>{
    fc.assert(fc.property(inputArb,fc.integer({min:1,max:10}),(items,perPage)=>{
      const totalPages=Math.max(1,Math.ceil(items.length/perPage));
      for(let p1=1;p1<=totalPages;p1++){
        for(let p2=p1+1;p2<=totalPages;p2++){
          const a=new Set(paginate(items,p1,perPage).items.map(i=>i.id));
          const b=paginate(items,p2,perPage).items.map(i=>i.id);
          if(b.some(id=>a.has(id)))return false;
        }
      }
      return true;
    }),{numRuns:300});
  });
  it('page sizes are perPage except possibly the last',()=>{
    fc.assert(fc.property(inputArb.filter(a=>a.length>0),fc.integer({min:1,max:10}),(items,perPage)=>{
      const totalPages=Math.ceil(items.length/perPage);
      for(let p=1;p<totalPages;p++){
        if(paginate(items,p,perPage).items.length!==perPage)return false;
      }
      const last=paginate(items,totalPages,perPage).items.length;
      return last>0&&last<=perPage;
    }),{numRuns:300});
  });
});

