import type {Clock} from '../clock';
export interface Post{id:string;title:string;publishedAt:number}
export async function* createNewsFeed(opts:{fetch:()=>Promise<Post[]>;clock:Clock;intervalMs:number;abort:AbortSignal}){
  while(!opts.abort.aborted){
    const batch=await opts.fetch();
    for(const post of batch)yield post;
    if(opts.abort.aborted)break;
    await new Promise(r=>setTimeout(r,opts.intervalMs));
  }
}

// src/feed/news-feed.test.ts
import {describe,it,expect,vi,beforeEach,afterEach} from 'vitest';
import {createNewsFeed,type Post} from './news-feed';
import {FakeClock} from '../clock';

async function take<T>(iter:AsyncIterable<T>,n:number):Promise<T[]>{
  const out:T[]=[];
  for await(const v of iter){
    out.push(v);
    if(out.length>=n)break;
  }
  return out;
}

beforeEach(()=>{vi.useFakeTimers();});
afterEach(()=>{vi.useRealTimers();});

describe('createNewsFeed',()=>{
  it('yields posts from fetch results in order',async()=>{
    const fetch=vi.fn().mockResolvedValueOnce([{id:'1',title:'A',publishedAt:1},{id:'2',title:'B',publishedAt:2}]);
    const abort=new AbortController();
    const iter=createNewsFeed({fetch,clock:new FakeClock(0),intervalMs:1000,abort:abort.signal});
    const promise=take(iter,2);
    await vi.advanceTimersByTimeAsync(0);
    const results=await promise;
    expect(results.map(p=>p.id)).toEqual(['1','2']);
  });
  it('aborts cleanly when AbortController signals',async()=>{
    const fetch=vi.fn().mockResolvedValue([{id:'1',title:'A',publishedAt:1}]);
    const abort=new AbortController();
    const iter=createNewsFeed({fetch,clock:new FakeClock(0),intervalMs:1000,abort:abort.signal});
    const promise=(async()=>{
      const out:Post[]=[];
      for await(const p of iter){out.push(p);if(out.length===1)abort.abort();}
      return out;
    })();
    await vi.runOnlyPendingTimersAsync();
    const out=await promise;
    expect(out).toHaveLength(1);
    expect(fetch).toHaveBeenCalledTimes(1);
  });
  it('does not call fetch after abort',async()=>{
    const fetch=vi.fn().mockResolvedValue([{id:'1',title:'A',publishedAt:1}]);
    const abort=new AbortController();
    abort.abort();
    const iter=createNewsFeed({fetch,clock:new FakeClock(0),intervalMs:1000,abort:abort.signal});
    const out:Post[]=[];
    for await(const p of iter)out.push(p);
    expect(out).toHaveLength(0);
    expect(fetch).not.toHaveBeenCalled();
  });
});

import { Suspense, use, useDeferredValue, useMemo, useState } from 'react';

interface Props { searchFn: (q: string) => Promise<string[]>; }

type ReadResults = (query: string) => Promise<string[]>;

function makeSearchCache(searchFn: Props['searchFn']): ReadResults {
  const cache = new Map<string, Promise<string[]>>();
  return (query: string) => {
    const key = query.trim();
    if (!cache.has(key)) cache.set(key, searchFn(key));
    return cache.get(key)!;
  };
}

function Results({ readResults, query }: { readResults: ReadResults; query: string }) {
  const results = use(readResults(query));
  return <ul>{results.map((r) => <li key={r}>{r}</li>)}</ul>;
}

export function Search({ searchFn }: Props) {
  const [query, setQuery] = useState('');
  const deferredQuery = useDeferredValue(query);
  const readResults = useMemo(() => makeSearchCache(searchFn), [searchFn]);
  const pending = query !== deferredQuery;

  return (
    <div>
      <input aria-label="search" value={query} onChange={(e) => setQuery(e.target.value)} />
      {pending && <span role="status">updating...</span>}
      <Suspense fallback={<div role="status">loading...</div>}>
        {deferredQuery ? <Results readResults={readResults} query={deferredQuery} /> : <p>type to search</p>}
      </Suspense>
    </div>
  );
}

