import type {Resolvers} from './generated';
export const orderResolvers:Resolvers={
  Query:{
    order:async(_,{id},ctx)=>{
      if(!ctx.user)throw new Error('Unauthorized');
      const order=await ctx.db.query('SELECT * FROM orders WHERE id=$1 AND user_id=$2',[id,ctx.user.id]);
      return order.rows[0]??null;
    }
  },
  Order:{
    items:async(order,_,ctx)=>{
      const r=await ctx.db.query('SELECT sku,qty,price_cents AS "priceCents" FROM order_items WHERE order_id=$1',[order.id]);
      return r.rows;
    }
  }
};

// src/graphql/orders.resolver.test.ts
import {describe,it,expect} from 'vitest';
import {graphql,buildSchema,parse} from 'graphql';
import {makeExecutableSchema} from '@graphql-tools/schema';
import {typeDefs} from './schema';
import {orderResolvers} from './orders.resolver';
import {pool,withTx} from '../../tests/setup/per-worker-db';

const schema=makeExecutableSchema({typeDefs,resolvers:orderResolvers});

describe('order resolvers',()=>{
  it('returns order with items via fragment',async()=>{
    await withTx(async(c)=>{
      await c.query("INSERT INTO users(id) VALUES('u1')");
      await c.query("INSERT INTO orders(id,user_id,total_cents) VALUES('o1','u1',1000)");
      await c.query("INSERT INTO order_items(order_id,sku,qty,price_cents) VALUES('o1','A',2,500)");
      const result=await graphql({
        schema,
        source:`query($id:ID!){ order(id:$id){ id total ...Items } } fragment Items on Order { items { sku qty priceCents } }`,
        variableValues:{id:'o1'},
        contextValue:{user:{id:'u1'},db:c}
      });
      expect(result.errors).toBeUndefined();
      expect(result.data?.order).toMatchObject({id:'o1',items:[{sku:'A',qty:2,priceCents:500}]});
    });
  });
  it('returns null for an order owned by another user (authorization)',async()=>{
    await withTx(async(c)=>{
      await c.query("INSERT INTO users(id) VALUES('u1'),('u2')");
      await c.query("INSERT INTO orders(id,user_id,total_cents) VALUES('o1','u1',1000)");
      const result=await graphql({
        schema,
        source:`{ order(id:"o1"){ id } }`,
        contextValue:{user:{id:'u2'},db:c}
      });
      expect(result.errors).toBeUndefined();
      expect(result.data?.order).toBeNull();
    });
  });
  it('returns errors[] when unauthorized (no user in context)',async()=>{
    await withTx(async(c)=>{
      const result=await graphql({
        schema,
        source:`{ order(id:"o1"){ id } }`,
        contextValue:{user:null,db:c}
      });
      expect(result.data?.order).toBeNull();
      expect(result.errors).toHaveLength(1);
      expect(result.errors?.[0].message).toMatch(/unauthorized/i);
    });
  });
});

