export interface SeededOrder{id:string;userId:string;totalCents:number}
export async function seedOrder(client:PoolClient,userId:string,overrides:Partial<{totalCents:number;status:string}>={}):Promise<SeededOrder>{
  const id=faker.string.uuid();
  const totalCents=overrides.totalCents??faker.number.int({min:100,max:100000});
  const status=overrides.status??'paid';
  await client.query('INSERT INTO orders(id,user_id,total_cents,status) VALUES($1,$2,$3,$4)',[id,userId,totalCents,status]);
