}

// tests/seed/order-item.seed.ts
import type {PoolClient} from 'pg';
import {faker} from '@faker-js/faker';
export interface SeededItem{sku:string;qty:number;priceCents:number}
export async function seedOrderItems(client:PoolClient,orderId:string,items:Partial<SeededItem>[]):Promise<SeededItem[]>{
  const seeded:SeededItem[]=[];
  for(const i of items){
    const item={sku:i.sku??faker.string.alphanumeric(8),qty:i.qty??1,priceCents:i.priceCents??100};
    await client.query('INSERT INTO order_items(order_id,sku,qty,price_cents) VALUES($1,$2,$3,$4)',[orderId,item.sku,item.qty,item.priceCents]);
    seeded.push(item);
  }
  return seeded;
}

