import {glob} from 'glob';
import {readFileSync} from 'node:fs';
interface Metrics{count:number;totalMs:number;files:string[]}
async function audit():Promise<void>{
  const buckets:Record<string,Metrics>={
    unit:{count:0,totalMs:0,files:[]},
    integration:{count:0,totalMs:0,files:[]},
    e2e:{count:0,totalMs:0,files:[]}
  };
  // Vitest JSON reporter output
  const report=JSON.parse(readFileSync('test-results.json','utf8')) as {testResults:Array<{name:string;perfStats:{runtime:number};assertionResults:Array<{status:string}>}>};
  for(const r of report.testResults){
    const bucket=r.name.includes('/e2e/')?'e2e':r.name.includes('/integration/')?'integration':'unit';
    buckets[bucket].count+=r.assertionResults.length;
    buckets[bucket].totalMs+=r.perfStats.runtime;
    buckets[bucket].files.push(r.name);
  }
  const total=Object.values(buckets).reduce((s,b)=>s+b.count,0);
  reporter.write('--- TEST PYRAMID ---');
  for(const [k,b] of Object.entries(buckets)){
    const pct=((b.count/total)*100).toFixed(1);
    const avg=b.count?Math.round(b.totalMs/b.count):0;
    reporter.write(`${k.padEnd(12)} ${b.count.toString().padStart(5)} tests (${pct}%) | ${avg}ms avg | ${(b.totalMs/1000).toFixed(1)}s total`);
  }
  // Targets
  const unitPct=(buckets.unit.count/total)*100;
  if(unitPct<60){console.error(`⚠️  Pyramid inverted: only ${unitPct.toFixed(0)}% unit tests (target ≥70%)`);process.exit(1);}
  if(buckets.unit.totalMs/buckets.unit.count>100){console.error(`⚠️  Unit tests slow: ${(buckets.unit.totalMs/buckets.unit.count).toFixed(0)}ms avg (target <50ms)`);}
  // Outliers
  const slow=report.testResults.filter(r=>r.name.includes('/unit/')&&r.perfStats.runtime>500);
  if(slow.length){reporter.write(`Slow unit tests:\n${slow.map(s=>`  ${s.name} (${s.perfStats.runtime}ms)`).join('\n')}`);}
}
audit();

