import {useForm} from 'react-hook-form';
import {zodResolver} from '@hookform/resolvers/zod';
import {z} from 'zod';

const ProfileSchema=z.object({
  displayName:z.string().min(2,'Too short').max(50,'Too long'),
  bio:z.string().max(500,'Bio cannot exceed 500 characters'),
  websiteUrl:z.string().url('Must be a valid URL').or(z.literal(''))
});
type ProfileValues=z.infer<typeof ProfileSchema>;

export function ProfileForm({onSubmit,defaultValues}:{onSubmit:(v:ProfileValues)=>void;defaultValues:ProfileValues}){
  const {register,handleSubmit,formState:{errors,isSubmitting}}=useForm<ProfileValues>({resolver:zodResolver(ProfileSchema),defaultValues,mode:'onBlur'});
  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      <label>Display name<input {...register('displayName')} aria-invalid={!!errors.displayName}/></label>
      {errors.displayName&&<span role="alert">{errors.displayName.message}</span>}
      <label>Bio<textarea {...register('bio')} aria-invalid={!!errors.bio}/></label>
      {errors.bio&&<span role="alert">{errors.bio.message}</span>}
      <label>Website<input {...register('websiteUrl')} aria-invalid={!!errors.websiteUrl}/></label>
      {errors.websiteUrl&&<span role="alert">{errors.websiteUrl.message}</span>}
      <button type="submit" disabled={isSubmitting}>Save</button>
    </form>
  );
}

