test('order status updates in real-time when changed server-side',async({page,request})=>{
  // Seed an order via API (test helper)
  const create=await request.post('/api/test/seed/order',{data:{status:'pending'}});
  const {id}=await create.json();
  await page.goto(`/orders/${id}`);
  // Wait for SSE connection + initial render
  const statusBadge=page.getByRole('status',{name:/order status/i});
  await expect(statusBadge).toHaveText('Pending');
  // Trigger the update via REAL API
  await request.patch(`/api/orders/${id}/status`,{data:{status:'shipped'}});
