test('SSE reconnects after network blip',async({page,context,request})=>{
  const create=await request.post('/api/test/seed/order',{data:{status:'pending'}});
  const {id}=await create.json();
  await page.goto(`/orders/${id}`);
  await expect(page.getByRole('status',{name:/order status/i})).toHaveText('Pending');
  // Simulate offline
  await context.setOffline(true);
  await page.waitForTimeout(500);
  await context.setOffline(false);
  // After reconnect, push a new update — UI should still receive it
  await request.patch(`/api/orders/${id}/status`,{data:{status:'delivered'}});
  await expect(page.getByRole('status',{name:/order status/i})).toHaveText('Delivered',{timeout:8000});
});

import { Buffer } from 'node:buffer';
export interface Cursor { createdAt: string; id: string }
export const encodeCursor = (c: Cursor): string => Buffer.from(JSON.stringify(c)).toString('base64url');
export function decodeCursor(s: string): Cursor {
  try {
    const o = JSON.parse(Buffer.from(s, 'base64url').toString('utf8')) as Partial<Cursor>;
    if (typeof o.createdAt !== 'string' || Number.isNaN(Date.parse(o.createdAt)) || typeof o.id !== 'string') throw new Error('shape');
    return { createdAt: o.createdAt, id: o.id };
  } catch { throw new Error('Invalid cursor'); }
}

// src/api/orders.list.ts
import type { RequestHandler } from 'express';
import { encodeCursor, decodeCursor } from '../pagination/cursor';
export const listOrders: RequestHandler = async (req, res, next) => {
  try {
    const limit = Math.min(50, Number(req.query.limit ?? 20));
    const cursor = req.query.cursor ? decodeCursor(String(req.query.cursor)) : null;
    const where = cursor ? 'WHERE (created_at,id) < ($1::timestamptz,$2)' : '';
    const params = cursor ? [cursor.createdAt, cursor.id] : [];
    const rows = (await req.app.locals.db.query(
      `SELECT id, created_at as "createdAt" FROM orders ${where} ORDER BY created_at DESC, id DESC LIMIT $${params.length + 1}`,
      [...params, limit + 1],
    )).rows;
    const hasMore = rows.length > limit;
    const items = rows.slice(0, limit);
    const nextCursor = hasMore && items.length
      ? encodeCursor({ createdAt: new Date(items.at(-1).createdAt).toISOString(), id: items.at(-1).id })
      : null;
    res.json({ items, nextCursor, hasMore });
  } catch (err) { next(err); }
};

