import { describe, it, expect } from 'vitest';
import request from 'supertest';
import { app } from '../app';
import { withTx } from '../../tests/setup/per-worker-db';

describe('GET /orders pagination', () => {
  it('paginates without overlap or skipped rows', async () => {
    await withTx(async (c) => {
      for (let i = 0; i < 5; i++) {
        await c.query(
          'INSERT INTO orders(id,user_id,created_at,status,total_cents) VALUES($1,$2,$3::timestamptz,$4,$5)',
          [`o${i}`, 'u1', new Date(Date.UTC(2026, 0, 1, 0, 0, 5 - i)).toISOString(), 'paid', 100],
        );
      }
      const seen = new Set<string>();
      let cursor: string | undefined;
      let pages = 0;
      while (true) {
        const r = await request(app).get(`/api/orders?limit=2${cursor ? `&cursor=${cursor}` : ''}`).expect(200);
        for (const item of r.body.items) {
          expect(seen.has(item.id), `duplicate ${item.id}`).toBe(false);
          seen.add(item.id);
        }
        pages++;
        if (!r.body.hasMore) break;
        cursor = r.body.nextCursor;
      }
      expect(seen.size).toBe(5);
      expect(pages).toBe(3);
    });
  });

  it('disambiguates by id when createdAt collides', async () => {
    await withTx(async (c) => {
      const ts = new Date(Date.UTC(2026, 0, 1)).toISOString();
      for (const id of ['a', 'b', 'c', 'd']) {
        await c.query('INSERT INTO orders(id,user_id,created_at,status,total_cents) VALUES($1,$2,$3::timestamptz,$4,$5)', [id, 'u1', ts, 'paid', 100]);
      }
      const seen = new Set<string>();
      let cursor: string | undefined;
      while (true) {
        const r = await request(app).get(`/api/orders?limit=2${cursor ? `&cursor=${cursor}` : ''}`).expect(200);
        r.body.items.forEach((i: { id: string }) => { expect(seen.has(i.id), `duplicate ${i.id}`).toBe(false); seen.add(i.id); });
        if (!r.body.hasMore) break;
        cursor = r.body.nextCursor;
      }
      expect(seen.size).toBe(4);
    });
  });

  it('returns 400 on malformed cursor', async () => {
    await request(app).get('/api/orders?cursor=not-base64').expect(400);
  });
});

export function canonicalUrl(input:string):string{
  const u=new URL(input);
  u.hostname=u.hostname.toLowerCase();
  if((u.protocol==='https:'&&u.port==='443')||(u.protocol==='http:'&&u.port==='80'))u.port='';
  const params=new URLSearchParams([...u.searchParams.entries()].sort(([a],[b])=>a.localeCompare(b)));
  u.search=params.toString();
  if(u.pathname!=='/'&&u.pathname.endsWith('/'))u.pathname=u.pathname.replace(/\/+$/,'');
  u.hash=''; // strip fragment
  return u.toString();
}

// src/url/canonical.property.test.ts
import {describe,it,expect} from 'vitest';
import fc from 'fast-check';
import {canonicalUrl} from './canonical';

describe('canonicalUrl properties',()=>{
  it('is idempotent',()=>{
    fc.assert(fc.property(fc.webUrl({withFragments:true,withQueryParameters:true}),(url)=>{
      const once=canonicalUrl(url);
      const twice=canonicalUrl(once);
      return once===twice;
    }),{numRuns:500});
  });
  it('produces same result for default-port and no-port',()=>{
    fc.assert(fc.property(fc.webUrl(),(url)=>{
      const u=new URL(url);
      if(u.protocol!=='https:')return true; // skip
      const withPort=`${u.protocol}//${u.hostname}:443${u.pathname}${u.search}`;
      const withoutPort=`${u.protocol}//${u.hostname}${u.pathname}${u.search}`;
      return canonicalUrl(withPort)===canonicalUrl(withoutPort);
    }),{numRuns:300});
  });
  it('is case-insensitive on host',()=>{
    fc.assert(fc.property(fc.webUrl(),(url)=>{
      const u=new URL(url);
      const upper=url.replace(u.hostname,u.hostname.toUpperCase());
      return canonicalUrl(url)===canonicalUrl(upper);
    }),{numRuns:300});
  });
  it('produces same result regardless of query param order',()=>{
    fc.assert(fc.property(fc.uniqueArray(fc.string({minLength:1,maxLength:5}).filter(s=>/^[a-z]+$/.test(s)),{minLength:2,maxLength:5}),(keys)=>{
      const a=`https://example.com/?${keys.map(k=>`${k}=v`).join('&')}`;
      const b=`https://example.com/?${[...keys].reverse().map(k=>`${k}=v`).join('&')}`;
      return canonicalUrl(a)===canonicalUrl(b);
    }),{numRuns:300});
  });
});

// Real mutant SURVIVES: changing `>= 0` to `> 0` doesn't break any test
// because tests don't cover the case `arr.length === 0`
// ADD A TEST that exercises empty arrays
export function lastOrUndefined<T>(arr:readonly T[]):T|undefined{
  return arr.length>=1?arr[arr.length-1]:undefined;
}

// Equivalent mutant: `i++` vs `i+=1` — semantically identical
// Document with disable comment + reason
export function indexOfBy<T>(arr:readonly T[],pred:(x:T)=>boolean):number{
  // Stryker disable next-line UpdateOperator -- ++ and +=1 are semantically identical for loop increment
  for(let i=0;i<arr.length;i++){
    if(pred(arr[i]))return i;
  }
  return -1;
}

// Equivalent mutant: changing `?? defaultValue` to `|| defaultValue`
// HERE they're equivalent because T is always truthy when present.
// Stryker disable next-line LogicalOperator -- T is bigint, never falsy when defined
export function withDefault(v:bigint|undefined,d:bigint):bigint{return v??d;}
// NOTE: if T could be 0 / '' / false, this would NOT be equivalent. Comment forces re-review on type change.

