export async function setup():Promise<void>{
  pg=await new PostgreSqlContainer('postgres:16.4-alpine')
    .withDatabase('test')
    .withUsername('test')
    .withPassword('test')
    .withReuse() // dev: reuse if already running; CI: starts fresh
    .start();
  process.env.TEST_DATABASE_URL=pg.getConnectionUri();
  redis=await new RedisContainer('redis:7.4-alpine').withReuse().start();
  process.env.TEST_REDIS_URL=redis.getConnectionUrl();
