  reporter.write(`Redis: ${redis.getConnectionUrl()}`);
}

export async function teardown():Promise<void>{
  // With withReuse, containers persist between runs — only stop in CI
  if(process.env.CI){
    await pg?.stop();
    await redis?.stop();
  }
}

