import {useVirtualizer} from '@tanstack/react-virtual';
import {useRef,forwardRef,useImperativeHandle} from 'react';
export interface VirtualListHandle{scrollToIndex:(i:number)=>void}
interface Props{items:string[]}
export const VirtualList=forwardRef<VirtualListHandle,Props>(function VirtualList({items},ref){
  const parent=useRef<HTMLDivElement>(null);
  const v=useVirtualizer({count:items.length,getScrollElement:()=>parent.current,estimateSize:()=>40,overscan:5});
  useImperativeHandle(ref,()=>({scrollToIndex:(i)=>v.scrollToIndex(i,{align:'start'})}),[v]);
  return (
    <div ref={parent} style={{height:400,overflow:'auto'}} role="grid">
      <div style={{height:v.getTotalSize(),position:'relative'}}>
        {v.getVirtualItems().map(vi=>(
          <div key={vi.key} role="row" data-index={vi.index} style={{position:'absolute',top:vi.start,height:vi.size,left:0,right:0}}>
            {items[vi.index]}
          </div>
        ))}
      </div>
    </div>
  );
});

