// scripts/flake-tracker.ts — run after each CI build
import {readFileSync,writeFileSync,existsSync} from 'node:fs';
interface TestResult{title:string;status:'passed'|'failed';retry:number}
const report=JSON.parse(readFileSync('test-results.json','utf8')) as {suites:Array<{specs:Array<{title:string;tests:Array<{results:TestResult[]}>}>}>};

const flakes:Record<string,{firstSeen:string;runs:number;flakes:number}>=existsSync('.flake-history.json')?JSON.parse(readFileSync('.flake-history.json','utf8')):{};

for(const suite of report.suites){
  for(const spec of suite.specs){
    for(const test of spec.tests){
      const results=test.results;
      const passed=results.some(r=>r.status==='passed');
      const failed=results.some(r=>r.status==='failed');
      const f=flakes[spec.title]??(flakes[spec.title]={firstSeen:new Date().toISOString(),runs:0,flakes:0});
      f.runs++;
      if(passed&&failed)f.flakes++; // retries to pass = flake signal
    }
  }
}
writeFileSync('.flake-history.json',JSON.stringify(flakes,null,2));

// Report tests over the threshold
const PROBLEM_RATE=0.02; // 2%
const DELETE_AGE_DAYS=14;
const now=Date.now();
for(const [title,f] of Object.entries(flakes)){
  if(f.runs<10)continue;
  const rate=f.flakes/f.runs;
  const ageDays=(now-new Date(f.firstSeen).getTime())/(1000*60*60*24);
  if(rate>=PROBLEM_RATE){
    if(ageDays>=DELETE_AGE_DAYS){
      console.error(`🚨 DELETE THIS TEST: '${title}' has been flaky ${(rate*100).toFixed(1)}% for ${ageDays.toFixed(0)} days`);
      process.exitCode=1;
    }else{
      console.warn(`⚠️  Flake watch: '${title}' ${(rate*100).toFixed(1)}% flake over ${f.runs} runs (${ageDays.toFixed(0)}/${DELETE_AGE_DAYS} days)`);
    }
  }
}

