import {useState,useRef,useEffect} from 'react';
interface Props{items:string[];onSelect:(item:string)=>void}
export function Dropdown({items,onSelect}:Props){
  const [open,setOpen]=useState(false);
  const [active,setActive]=useState(0);
  const triggerRef=useRef<HTMLButtonElement>(null);
  const menuRef=useRef<HTMLUListElement>(null);
  useEffect(()=>{if(open)menuRef.current?.focus();},[open]);
  function handleKey(e:React.KeyboardEvent){
    if(e.key==='ArrowDown'){e.preventDefault();setActive((i)=>(i+1)%items.length);}
    else if(e.key==='ArrowUp'){e.preventDefault();setActive((i)=>(i-1+items.length)%items.length);}
    else if(e.key==='Home'){e.preventDefault();setActive(0);}
    else if(e.key==='End'){e.preventDefault();setActive(items.length-1);}
    else if(e.key==='Enter'){e.preventDefault();onSelect(items[active]);setOpen(false);triggerRef.current?.focus();}
    else if(e.key==='Escape'){e.preventDefault();setOpen(false);triggerRef.current?.focus();}
  }
  return (
    <div>
      <button ref={triggerRef} aria-haspopup="menu" aria-expanded={open} onClick={()=>setOpen(o=>!o)}>Open</button>
      {open&&(
        <ul ref={menuRef} role="menu" tabIndex={-1} onKeyDown={handleKey} aria-activedescendant={`item-${active}`}>
          {items.map((it,i)=>(
            <li key={it} id={`item-${i}`} role="menuitem" aria-selected={i===active}>{it}</li>
          ))}
        </ul>
      )}
    </div>
  );
}

