export class LRU<K,V>{
  private map=new Map<K,V>();
  constructor(public readonly capacity:number){if(capacity<1)throw new Error('capacity must be >= 1');}
  get(k:K):V|undefined{
    if(!this.map.has(k))return undefined;
    const v=this.map.get(k)!;
    this.map.delete(k);
    this.map.set(k,v); // refresh recency
    return v;
  }
  set(k:K,v:V):void{
    if(this.map.has(k))this.map.delete(k);
    this.map.set(k,v);
    while(this.map.size>this.capacity){
      const oldest=this.map.keys().next().value as K;
      this.map.delete(oldest);
    }
  }
  delete(k:K):boolean{return this.map.delete(k);}
  get size():number{return this.map.size;}
}

// src/cache/lru.property.test.ts
import {describe,it,expect} from 'vitest';
import fc from 'fast-check';
import {LRU} from './lru';

type Cmd={t:'set';k:number;v:number}|{t:'get';k:number}|{t:'delete';k:number};
const keyArb=fc.integer({min:0,max:5});
const cmdArb=fc.oneof(
  fc.record({t:fc.constant('set' as const),k:keyArb,v:fc.integer({min:0,max:1000})}),
  fc.record({t:fc.constant('get' as const),k:keyArb}),
  fc.record({t:fc.constant('delete' as const),k:keyArb})
);

function runModel(cmds:Cmd[],capacity:number):Map<number,number>{
  const m=new Map<number,number>();
  for(const c of cmds){
    if(c.t==='set'){if(m.has(c.k))m.delete(c.k);m.set(c.k,c.v);while(m.size>capacity){m.delete(m.keys().next().value as number);}}
    else if(c.t==='get'){if(m.has(c.k)){const v=m.get(c.k)!;m.delete(c.k);m.set(c.k,v);}}
    else if(c.t==='delete')m.delete(c.k);
  }
  return m;
}

describe('LRU properties',()=>{
  it('size never exceeds capacity',()=>{
    fc.assert(fc.property(fc.array(cmdArb,{maxLength:50}),fc.integer({min:1,max:5}),(cmds,cap)=>{
      const lru=new LRU<number,number>(cap);
      for(const c of cmds){
        if(c.t==='set')lru.set(c.k,c.v);
        else if(c.t==='get')lru.get(c.k);
        else lru.delete(c.k);
        if(lru.size>cap)return false;
      }
      return true;
    }),{numRuns:500});
  });
  it('contents agree with reference model',()=>{
    fc.assert(fc.property(fc.array(cmdArb,{maxLength:50}),fc.integer({min:1,max:5}),(cmds,cap)=>{
      const lru=new LRU<number,number>(cap);
      for(const c of cmds){
        if(c.t==='set')lru.set(c.k,c.v);
        else if(c.t==='get')lru.get(c.k);
        else lru.delete(c.k);
      }
      const model=runModel(cmds,cap);
      for(let k=0;k<=5;k++){
        const a=lru.get(k); // note: get mutates recency — same in model below
        const expected=model.get(k);
        if(a!==expected)return false;
        // re-do the get on the model to mirror the recency update
        if(expected!==undefined){model.delete(k);model.set(k,expected);}
      }
      return true;
    }),{numRuns:500});
  });
});

