  test:(v:unknown)=>v!==null&&typeof v==='object'&&!(v instanceof Date)&&!(v instanceof Map)&&!(v instanceof Set),
  serialize:(v,config,indentation,depth,refs,printer)=>printer(canonical(v),config,indentation,depth,refs)
});

