import type {RequestHandler} from 'express';
import type {Pool} from 'pg';
import type {Redis} from 'ioredis';

export function healthz(opts:{db:Pool;redis:Redis}):RequestHandler{
  return async(_req,res)=>{
    const checks:Record<string,{ok:boolean;ms?:number;error?:string}>={};
    async function check(name:string,fn:()=>Promise<unknown>):Promise<void>{
      const start=Date.now();
      try{await fn();checks[name]={ok:true,ms:Date.now()-start};}
      catch(e){checks[name]={ok:false,error:e instanceof Error?e.message:'unknown'};}
    }
    await Promise.all([
      check('db',()=>opts.db.query('SELECT 1')),
      check('redis',()=>opts.redis.ping())
    ]);
    const ok=Object.values(checks).every(c=>c.ok);
    res.status(ok?200:503).json({status:ok?'ok':'degraded',checks});
  };
}

